<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Ubuntu Desktop</title>
<style>
  *, *::before, *::after { margin: 0; padding: 0; box-sizing: border-box; }

  body {
    overflow: hidden;
    font-family: 'Ubuntu', 'Segoe UI', system-ui, -apple-system, sans-serif;
    user-select: none;
    height: 100vh;
    width: 100vw;
  }

  /* ── Desktop Root ── */
  #desktop {
    position: fixed;
    top: 0; left: 0; right: 0; bottom: 0;
    background: linear-gradient(135deg, #2c001e 0%, #4a0033 25%, #77216f 50%, #e95420 80%, #ff790d 100%);
    background-size: cover;
    z-index: 0;
  }

  /* ── Top Bar ── */
  #topbar {
    position: fixed;
    top: 0; left: 0; right: 0;
    height: 28px;
    background: rgba(15, 15, 15, 0.95);
    backdrop-filter: blur(12px);
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 0 12px;
    z-index: 1000;
    color: #eee;
    font-size: 13px;
    letter-spacing: 0.2px;
  }
  #topbar .left { display: flex; align-items: center; gap: 6px; }
  #topbar .ubuntu-logo {
    width: 18px; height: 18px;
    background: radial-gradient(circle, #e95420 3px, transparent 4px);
    border-radius: 50%;
    position: relative;
  }
  #topbar .center { color: #ccc; font-size: 12px; }
  #topbar .right { display: flex; align-items: center; gap: 14px; color: #ddd; font-size: 12px; }

  /* ── Taskbar / Dock ── */
  #taskbar {
    position: fixed;
    bottom: 8px;
    left: 50%;
    transform: translateX(-50%);
    display: flex;
    align-items: center;
    gap: 6px;
    padding: 6px 12px;
    background: rgba(30, 30, 30, 0.85);
    backdrop-filter: blur(16px);
    border-radius: 16px;
    z-index: 1000;
    border: 1px solid rgba(255,255,255,0.08);
    box-shadow: 0 4px 24px rgba(0,0,0,0.4);
  }

  .dock-btn {
    width: 44px; height: 44px;
    border-radius: 12px;
    border: none;
    cursor: pointer;
    display: flex;
    align-items: center;
    justify-content: center;
    transition: all 0.2s ease;
    position: relative;
  }
  .dock-btn:hover { transform: scale(1.15); }
  .dock-btn:active { transform: scale(0.95); }

  #open-files {
    background: linear-gradient(135deg, #3e8e41, #2f6b30);
    color: white;
    font-size: 20px;
  }
  #open-notepad {
    background: linear-gradient(135deg, #4a90d9, #357abd);
    color: white;
    font-size: 20px;
  }

  .dock-btn .dot-indicator {
    position: absolute;
    bottom: -4px;
    width: 4px; height: 4px;
    border-radius: 50%;
    background: #e95420;
    opacity: 0;
    transition: opacity 0.2s;
  }
  .dock-btn.active .dot-indicator { opacity: 1; }

  /* ── Window Base ── */
  .app-window {
    position: absolute;
    min-width: 360px;
    min-height: 240px;
    background: #2d2d2d;
    border-radius: 10px;
    box-shadow: 0 8px 40px rgba(0,0,0,0.5), 0 0 0 1px rgba(255,255,255,0.06);
    display: flex;
    flex-direction: column;
    overflow: hidden;
    z-index: 100;
    transition: box-shadow 0.2s;
  }
  .app-window.focused {
    box-shadow: 0 12px 56px rgba(0,0,0,0.6), 0 0 0 1px rgba(255,255,255,0.1);
    z-index: 200;
  }

  .win-titlebar {
    height: 38px;
    background: #3a3a3a;
    display: flex;
    align-items: center;
    padding: 0 12px;
    cursor: grab;
    flex-shrink: 0;
    border-bottom: 1px solid rgba(255,255,255,0.04);
  }
  .win-titlebar:active { cursor: grabbing; }

  .win-titlebar .title-text {
    color: #ddd;
    font-size: 13px;
    font-weight: 500;
    flex: 1;
    text-align: center;
    margin-right: 60px;
    letter-spacing: 0.2px;
  }

  .win-controls {
    position: absolute;
    right: 8px;
    display: flex;
    gap: 7px;
  }
  .win-controls button {
    width: 14px; height: 14px;
    border-radius: 50%;
    border: none;
    cursor: pointer;
    transition: opacity 0.15s;
    font-size: 0;
    line-height: 1;
  }
  .win-controls button:hover { opacity: 0.8; }
  .btn-minimize { background: #f5c542; }
  .btn-maximize { background: #46d166; }
  .win-close {
    background: #e95420 !important;
    color: white !important;
    font-size: 10px !important;
    line-height: 14px !important;
    text-align: center;
    width: 18px !important;
    height: 18px !important;
    border-radius: 50% !important;
    cursor: pointer !important;
    border: none !important;
    font-weight: bold;
    display: flex;
    align-items: center;
    justify-content: center;
    padding: 0;
    margin-left: 4px;
  }

  .win-body {
    flex: 1;
    overflow: auto;
    background: #2d2d2d;
    color: #e0e0e0;
  }

  /* ── Files App ── */
  #files-window { top: 60px; left: 80px; width: 720px; height: 480px; }

  .files-toolbar {
    display: flex;
    align-items: center;
    gap: 8px;
    padding: 8px 14px;
    background: #363636;
    border-bottom: 1px solid rgba(255,255,255,0.05);
  }

  #files-up {
    width: 32px; height: 32px;
    border-radius: 8px;
    border: none;
    background: rgba(255,255,255,0.06);
    color: #ccc;
    font-size: 16px;
    cursor: pointer;
    display: flex;
    align-items: center;
    justify-content: center;
    transition: background 0.15s;
  }
  #files-up:hover { background: rgba(255,255,255,0.12); color: #fff; }

  #files-path {
    flex: 1;
    background: rgba(0,0,0,0.3);
    border: 1px solid rgba(255,255,255,0.08);
    border-radius: 8px;
    padding: 6px 14px;
    color: #e95420;
    font-size: 13px;
    font-family: 'Ubuntu Mono', 'Fira Code', monospace;
    outline: none;
  }

  .files-list {
    padding: 8px;
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(90px, 1fr));
    gap: 6px;
  }

  .fs-item {
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    padding: 12px 8px;
    border-radius: 10px;
    cursor: pointer;
    transition: background 0.15s;
    gap: 6px;
    min-height: 90px;
  }
  .fs-item:hover { background: rgba(255,255,255,0.07); }
  .fs-item:active { background: rgba(255,255,255,0.12); }

  .fs-icon { font-size: 36px; line-height: 1; }
  .fs-name {
    font-size: 11px;
    color: #ccc;
    text-align: center;
    word-break: break-word;
    max-width: 100%;
    line-height: 1.3;
  }

  /* ── Notepad App ── */
  #notepad-window { top: 80px; left: 200px; width: 640px; height: 500px; }

  .notepad-toolbar {
    display: flex;
    align-items: center;
    gap: 8px;
    padding: 6px 12px;
    background: #363636;
    border-bottom: 1px solid rgba(255,255,255,0.05);
  }

  #new-tab {
    height: 30px;
    padding: 0 14px;
    border-radius: 8px;
    border: none;
    background: linear-gradient(135deg, #e95420, #c74216);
    color: white;
    font-size: 12px;
    font-weight: 600;
    cursor: pointer;
    transition: all 0.15s;
    display: flex;
    align-items: center;
    gap: 4px;
  }
  #new-tab:hover { background: linear-gradient(135deg, #ff6b3a, #e95420); transform: scale(1.03); }

  #tabs {
    display: flex;
    align-items: center;
    gap: 2px;
    flex: 1;
    overflow-x: auto;
    scrollbar-width: none;
  }
  #tabs::-webkit-scrollbar { display: none; }

  .tab {
    padding: 5px 14px;
    border-radius: 8px;
    font-size: 12px;
    color: #aaa;
    cursor: pointer;
    white-space: nowrap;
    transition: all 0.15s;
    display: flex;
    align-items: center;
    gap: 6px;
    border: none;
    background: transparent;
    flex-shrink: 0;
  }
  .tab:hover { background: rgba(255,255,255,0.07); color: #ddd; }
  .tab.active {
    background: rgba(233, 84, 32, 0.2);
    color: #e95420;
    font-weight: 600;
  }

  .tab-close {
    width: 16px; height: 16px;
    border-radius: 50%;
    border: none;
    background: transparent;
    color: #888;
    font-size: 10px;
    cursor: pointer;
    display: flex;
    align-items: center;
    justify-content: center;
    transition: all 0.15s;
    flex-shrink: 0;
  }
  .tab-close:hover { background: rgba(233,84,32,0.4); color: white; }

  #editor-wrap {
    flex: 1;
    display: flex;
    flex-direction: column;
    overflow: hidden;
  }

  #editor {
    flex: 1;
    background: #1e1e1e;
    color: #d4d4d4;
    border: none;
    resize: none;
    padding: 16px;
    font-family: 'Ubuntu Mono', 'Fira Code', 'Consolas', monospace;
    font-size: 14px;
    line-height: 1.7;
    outline: none;
    tab-size: 2;
    overflow-y: auto;
  }

  /* ── Scrollbar Styling ── */
  ::-webkit-scrollbar { width: 8px; height: 8px; }
  ::-webkit-scrollbar-track { background: transparent; }
  ::-webkit-scrollbar-thumb { background: rgba(255,255,255,0.15); border-radius: 4px; }
  ::-webkit-scrollbar-thumb:hover { background: rgba(255,255,255,0.25); }

  /* ── Animations ── */
  @keyframes windowOpen {
    from { opacity: 0; transform: scale(0.92) translateY(10px); }
    to { opacity: 1; transform: scale(1) translateY(0); }
  }
  .app-window.opening { animation: windowOpen 0.2s ease-out forwards; }

  /* ── Resize Handle ── */
  .resize-handle {
    position: absolute;
    bottom: 0; right: 0;
    width: 16px; height: 16px;
    cursor: nwse-resize;
    z-index: 10;
  }
</style>
</head>
<body>

<!-- Desktop -->
<div id="desktop">

  <!-- Top Bar -->
  <div id="topbar">
    <div class="left">
      <div class="ubuntu-logo"></div>
      <span style="font-weight:600;letter-spacing:0.5px;">Activities</span>
    </div>
    <div class="center" id="clock-display"></div>
    <div class="right">
      <span>🔊</span>
      <span>📶</span>
