<script>
(function() {
  'use strict';

  // ════════════════════════════════════════
  // Clock
  // ════════════════════════════════════════
  function updateClock() {
    const now = new Date();
    const opts = { weekday: 'short', month: 'short', day: 'numeric' };
    document.getElementById('clock-display').textContent = now.toLocaleDateString('en-US', opts);
    document.getElementById('topbar-time').textContent = now.toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit' });
  }
  updateClock();
  setInterval(updateClock, 10000);

  // ════════════════════════════════════════
  // Window Management (drag, focus, close)
  // ════════════════════════════════════════
  let topZ = 200;
  const windows = {};

  function bringToFront(winId) {
    const el = document.getElementById(winId);
    if (!el || !el.style.display || el.style.display === 'none') return;
    topZ++;
    el.style.zIndex = topZ;
    el.classList.add('focused');
    // Remove focused from others
    document.querySelectorAll('.app-window').forEach(w => {
      if (w.id !== winId) w.classList.remove('focused');
    });
  }

  function initDrag(winId) {
    const win = document.getElementById(winId);
    const titlebar = win.querySelector('.win-titlebar');
    let offsetX, offsetY, dragging = false;

    titlebar.addEventListener('mousedown', (e) => {
      if (e.target.classList.contains('win-close') || e.target.closest('.win-controls')) return;
      bringToFront(winId);
      const rect = win.getBoundingClientRect();
      offsetX = e.clientX - rect.left;
      offsetY = e.clientY - rect.top;
      dragging = true;
      titlebar.style.cursor = 'grabbing';
      e.preventDefault();
    });

    document.addEventListener('mousemove', (e) => {
      if (!dragging) return;
      win.style.transition = 'none';
      win.style.left = Math.max(0, e.clientX - offsetX) + 'px';
      win.style.top = Math.max(28, e.clientY - offsetY) + 'px';
    });

    document.addEventListener('mouseup', () => {
      if (dragging) {
        dragging = false;
        titlebar.style.cursor = 'grab';
        win.style.transition = '';
      }
    });

    win.addEventListener('mousedown', () => bringToFront(winId));
  }

  // ════════════════════════════════════════
  // Files App — Filesystem Data
  // ════════════════════════════════════════
  const filesystem = {
    '/': {
      bin: 'folder', etc: 'folder', home: 'folder', usr: 'folder', var: 'folder',
      lib: 'folder', tmp: 'folder', root: 'folder', sbin: 'folder', dev: 'folder'
    },
    '/etc': {
      passwd: 'file', hosts: 'file', fstab: 'file', sshd_config: 'file',
      hostname: 'file', resolv.conf: 'file', profile: 'file', bashrc: 'file',
      default: 'folder', init.d: 'folder'
    },
    '/etc/default': { grub: 'file', user: 'file' },
    '/etc/init.d': { networking: 'script', cron: 'script', ssh: 'script' },
    '/home': { user: 'folder', guest: 'folder' },
    '/home/user': {
      Documents: 'folder', Downloads: 'folder', Pictures: 'folder',
      Music: 'folder', Videos: 'folder', Desktop: 'folder',
      '.bashrc': 'file', '.profile': 'file', '.ssh': 'folder',
      notes.txt: 'file', todo.md: 'file'
    },
    '/home/user/Documents': {
      report.pdf: 'file', resume.docx: 'file', project_plan.md: 'file',
      work: 'folder', personal: 'folder'
    },
    '/home/user/Documents/work': { meeting_notes.txt: 'file', slides.pptx: 'file' },
    '/home/user/Documents/personal': { diary.txt: 'file', recipes.md: 'file' },
    '/home/user/Downloads': { ubuntu.iso: 'file', wallpaper.png: 'file', archive.tar.gz: 'file' },
    '/home/user/Pictures': { screenshot.png: 'file', vacation: 'folder', icons: 'folder' },
    '/home/user/Pictures/vacation': { beach.jpg: 'file', mountains.jpg: 'file' },
    '/home/user/Pictures/icons': { home.svg: 'file', settings.svg: 'file' },
    '/home/user/Music': { playlist.m3u: 'file', favorite.mp3: 'file' },
    '/home/user/Videos': { tutorial.mp4: 'file' },
    '/home/user/Desktop': { shortcut.desktop: 'file' },
    '/home/user/.ssh': { id_rsa: 'file', id_rsa.pub: 'file', known_hosts: 'file' },
    '/home/guest': { Desktop: 'folder' },
    '/home/guest/Desktop': {},
    '/usr': { bin: 'folder', lib: 'folder', share: 'folder', local: 'folder' },
    '/usr/bin': { python3: 'script', node: 'script', gcc: 'script', vim: 'script', nano: 'script' },
    '/usr/lib': { x86_64-linux-gnu: 'folder' },
    '/usr/share': { applications: 'folder', doc: 'folder', locale: 'folder' },
    '/usr/local': { bin: 'folder', lib: 'folder' },
    '/var': { log: 'folder', cache: 'folder', tmp: 'folder', www: 'folder' },
    '/var/log': { syslog: 'file', auth.log: 'file', kern.log: 'file', dpkg.log: 'file' },
    '/var/cache': {},
    '/var/tmp': {},
    '/var/www': { html: 'folder' },
    '/var/www/html': { index.html: 'file' },
    '/lib': { modules: 'folder', x86_64-linux-gnu: 'folder' },
    '/tmp': { session_cache: 'folder' },
    '/tmp/session_cache': {},
    '/root': { .bashrc: 'file', .profile: 'file' },
    '/sbin': { fdisk: 'script', mount: 'script', reboot: 'script' },
    '/dev': { sda: 'block', null: 'char', zero: 'char' }
  };

  // Ensure all paths exist in filesystem object
  function ensurePath(path) {
    if (!filesystem[path]) filesystem[path] = {};
    return filesystem[path];
  }

  let currentFilesPath = '/';

  const icons = {
    folder: '📁', file: '📄', script: '⚙️', block: '💾', char: '🔌'
  };

  function renderFiles() {
    const list = document.getElementById('files-list');
    const pathInput = document.getElementById('files-path');
    pathInput.value = currentFilesPath;
    list.innerHTML = '';

    const dir = filesystem[currentFilesPath] || {};
    const entries = Object.entries(dir);

    if (entries.length === 0) {
      const empty = document.createElement('div');
      empty.style.cssText = 'grid-column:1/-1;text-align:center;padding:40px;color:#888;font-size:13px;';
      empty.textContent = 'This folder is empty';
      list.appendChild(empty);
      return;
    }

    // Sort: folders first, then files alphabetically
    entries.sort((a, b) => {
      if (a[1] === 'folder' && b[1] !== 'folder') return -1;
      if (a[1] !== 'folder' && b[1] === 'folder') return 1;
      return a[0].localeCompare(b[0]);
    });

    entries.forEach(([name, type]) => {
      const item = document.createElement('div');
      item.className = 'fs-item';
      item.innerHTML = `<span class="fs-icon">${icons[type] || '📄'}</span><span class="fs-name">${name}</span>`;

      // Double-click to navigate into folders
      if (type === 'folder') {
        item.addEventListener('dblclick', () => {
          currentFilesPath = currentFilesPath === '/' ? '/' + name : currentFilesPath + '/' + name;
          renderFiles();
        });
      }

      list.appendChild(item);
    });
  }

  document.getElementById('files-up').addEventListener('click', () => {
    if (currentFilesPath === '/') return;
    const parts = currentFilesPath.split('/').filter(Boolean);
    parts.pop();
    currentFilesPath = '/' + parts.join('/') || '/';
    renderFiles();
  });

  // ════════════════════════════════════════
  // Notepad App — Tabbed Editor with Persistence
  // ════════════════════════════════════════
  const STORAGE_KEY = 'notepad_tabs_v1';

  function loadTabs() {
    try {
      return JSON.parse(localStorage.getItem(STORAGE_KEY)) || [];
    } catch { return []; }
  }

  function saveTabs(tabs) {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(tabs));
  }

  let tabs = loadTabs();
  let activeTabIndex = -1;

  if (tabs.length === 0) {
    tabs.push({ name: 'Untitled', content: '' });
  }
  activeTabIndex = Math.min(activeTabIndex >= 0 ? activeTabIndex : 0, tabs.length - 1);

  function renderTabs() {
    const container = document.getElementById('tabs');
    container.innerHTML = '';

    tabs.forEach((tab, i) => {
      const el = document.createElement('button');
      el.className = 'tab' + (i === activeTabIndex ? ' active' : '');
      el.innerHTML = `<span>${escapeHtml(tab.name)}</span>`;

      if (tabs.length > 1) {
        const closeBtn = document.createElement('button');
        closeBtn.className = 'tab-close';
        closeBtn.textContent = '×';
        closeBtn.addEventListener('click', (e) => {
          e.stopPropagation();
          closeTab(i);
        });
        el.appendChild(closeBtn);
      }

      el.addEventListener('click', () => {
        activeTabIndex = i;
        renderTabs();
        document.getElementById('editor').value = tabs[i].content;
      });

      container.appendChild(el);
    });
  }

  function escapeHtml(str) {
    return str.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
  }

  function closeTab(index) {
    if (tabs.length <= 1) return;
    tabs.splice(index, 1);
    saveTabs(tabs);
    if (activeTabIndex >= tabs.length) activeTabIndex = tabs.length - 1;
    renderTabs();
    document.getElementById('editor').value = tabs[activeTabIndex].content;
  }

  function createNewTab() {
    const num = tabs.length + 1;
    tabs.push({ name: 'Untitled ' + num, content: '' });
    activeTabIndex = tabs.length - 1;
    saveTabs(tabs);
    renderTabs();
    document.getElementById('editor').value = '';
  }

  function syncEditor() {
    if (activeTabIndex >= 0 && activeTabIndex < tabs.length) {
      const val = document.getElementById('editor').value;
      tabs[activeTabIndex].content = val;
      saveTabs(tabs);
    }
  }

  // Debounced save
  let saveTimeout;
  function debouncedSave() {
    clearTimeout(saveTimeout);
    saveTimeout = setTimeout(syncEditor, 300);
  }

  document.getElementById('editor').addEventListener('input', debouncedSave);

  document.getElementById('new-tab').addEventListener('click', createNewTab);

  // ════════════════════════════════════════
  // Window Open / Close Logic
  // ════════════════════════════════════════
  function openWindow(winId, dockBtnId) {
    const win = document.getElementById(winId);
    if (win.style.display === 'none') {
      win.style.display = 'flex';
      win.classList.add('opening');
      setTimeout(() => win.classList.remove('opening'), 200);
      bringToFront(winId);

      // Dock indicator
      const dockBtn = document.getElementById(dockBtnId);
      if (dockBtn) dockBtn.classList.add('active');

      // Init app-specific rendering
      if (winId === 'files-window') renderFiles();
      if (winId === 'notepad-window') {
        renderTabs();
        if (activeTabIndex >= 0 && activeTabIndex < tabs.length) {
          document.getElementById('editor').value = tabs[activeTabIndex].content;
        }
      }
    } else {
      bringToFront(winId);
    }
  }

  function closeWindow(winId, dockBtnId) {
    const win = document.getElementById(winId);
    win.style.display = 'none';
    win.classList.remove('focused');

    // Dock indicator
    const dockBtn = document.getElementById(dockBtnId);
    if (dockBtn) dockBtn.classList.remove('active');
  }

  // Launcher buttons
  document.getElementById('open-files').addEventListener('click', () => openWindow('files-window', 'open-files'));
  document.getElementById('open-notepad').addEventListener('click', () => openWindow('notepad-window', 'open-notepad'));

  // Close buttons (class .win-close)
  document.querySelectorAll('.win-close').forEach(btn => {
    btn.addEventListener('click', (e) => {
      e.stopPropagation();
      const win = btn.closest('.app-window');
      if (!win) return;
      closeWindow(win.id, win.id === 'files-window' ? 'open-files' : 'open-notepad');
    });
  });

  // ════════════════════════════════════════
  // Initialize Drag for all windows
  // ════════════════════════════════════════
  initDrag('files-window');
  initDrag('notepad-window');

})();
